          ) : null}
        </ModalGateway>
      </div>

      <div className="projects-container">
        <h1>U.S. Department of Homeland Security</h1>
        <p>Collaborated closely with technology and operations experts to analyze over 1000 data points
        and design resilient TSA airport checkpoint systems, resulting in a 15% decrease in wait times.</p>
        <Gallery photos={CAOEPhotos} onClick={openLightbox} />
        <ModalGateway>
          {viewerIsOpen ? (
            <Modal onClose={closeLightbox}>
