      </div>

      <div className="projects-container">
        <h1>Supplemental Instruction</h1>
        <p>Led hour-long, in-person, and remote sessions 4 times a week for Programming with C, providing comprehensive
support to over 500 students in data structures, algorithms, recursion, dynamic memory, file I/O, etc.</p>
        <Gallery photos={SIPhotos} onClick={openLightbox} />
        <ModalGateway>
          {viewerIsOpen ? (
            <Modal onClose={closeLightbox}>
              <Carousel
                currentIndex={currentImage}
                views={mercPhotos.map(x => ({
                  ...x,
                  srcset: x.srcSet,
                  caption: x.title
                }))}
              />
            </Modal>
          ) : null}
        </ModalGateway>
      </div>

    </div>


  );
}
